Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port.

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
dotnet add package xunit
```

### Example test

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                clientInfo = new { name = "test-client", version = "1.0" },
                capabilities = new { }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // Initialize first (required by MCP)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeSession() { /* ... */ }
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real port** | `WebApplicationFactory` uses an in-memory `TestServer` |
| **Override services** | Use `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in mocks (e.g., fake DB) |
| **Stateful sessions** | If your server uses Streamable HTTP with session tokens, capture the `Mcp-Session-Id` header from `initialize` and attach it to subsequent requests |
| **SSE streams** | Read `text/event-stream` responses with `ReadAsStreamAsync()` + `StreamReader` line-by-line |
| **`Program` visibility** | If `Program` is implicit (top-level statements), add `public partial class Program { }` at the bottom of `Program.cs` |

This gives you full HTTP-level fidelity (headers, status codes, content negotiation) with zero network overhead.
